#!/usr/bin/perl

use strict;
use warnings;

use DBI;

my $dsn = "DBI:mysql:database=users";
my $username = param("username");
my $password = param("password");

my $dbh = DBI->connect($dsn, $username, $password) or die $!;

my $query = "SELECT * FROM users WHERE username='$username' AND password='$password'";
my $sth = $dbh->prepare($query);
$sth->execute();

my @rows = ();
while (my $row = $sth->fetchrow_hashref()) {
    push(@rows, $row);
}

if (@rows) {
    # user is logged in successfully
    print "Logged in successfully\n";
} else {
    # user is not found or incorrect credentials
    print "Incorrect username and/or password\n";
}